pub ghost enum GPDEView {
    Directory {
        addr: usize,
        P: bool,
        RW: bool,
        US: bool,
        PWT: bool,
        PCD: bool,
        XD: bool,
    },
    Page {
        addr: usize,
        P: bool,
        RW: bool,
        US: bool,
        PWT: bool,
        PCD: bool,
        G: bool,
        PAT: bool,
        XD: bool,
    },
    Invalid,
}

impl View for GPDE {
    type V = GPDEView;
    closed spec fn view(&self) -> GPDEView {
        match self {
            GPDE::Directory { addr, P, RW, US, PWT, PCD, XD } =>
                GPDEView::Directory { addr: *addr, P: *P, RW: *RW, US: *US, PWT: *PWT, PCD: *PCD, XD: *XD },
            GPDE::Page { addr, P, RW, US, PWT, PCD, G, PAT, XD } =>
                GPDEView::Page { addr: *addr, P: *P, RW: *RW, US: *US, PWT: *PWT, PCD: *PCD, G: *G, PAT: *PAT, XD: *XD },
            GPDE::Invalid => GPDEView::Invalid,
        }
    }
}

